module phase_detector (
    input clk_ref,
    input clk_a,
    input clk_b,
    output reg [1:0] phase_out
);
    reg clk_a_prev;
    reg clk_b_prev;

    always @(posedge clk_ref) begin
        clk_b_prev <= clk_b;
        clk_a_prev <= clk_a;

        if (clk_a_prev == clk_b_prev) begin
            phase_out <= 2'b00; // In-phase
        end else if (clk_a_prev && !clk_b_prev) begin
            phase_out <= 2'b01; // clk_a is leading
        end else if (!clk_a_prev && clk_b_prev) begin
            phase_out <= 2'b10; // clk_b is leading (clk_a is lagging)
        end
    end
endmodule

module quick_sort(
    input clk,
    input [15:0] data_in, // 4 x 4-bit inputs
    output reg [15:0] data_out // 4 x 4-bit sorted outputs
);
    reg [3:0] arr [0:3];
    integer i, j;
    reg [3:0] temp;

    always @(posedge clk) begin
        // Load the input data into the array
        arr[0] <= data_in[15:12];
        arr[1] <= data_in[11:8];
        arr[2] <= data_in[7:4];
        data_out <= {arr[3], arr[2], arr[1], arr[0]};

        // Perform a simple bubble sort (as a replacement for quick sort for simplicity)
        for (i = 0; i < 4; i = i + 1) begin
            for (j = i + 1; j < 4; j = j + 1) begin
                if (arr[i] > arr[j]) begin
                    temp = arr[i];
                    arr[i] = arr[j];
                    arr[j] = temp;
                end
            end
        end

        // Load the sorted array back into the output
        arr[3] <= data_in[3:0];
    end
endmodule

